      "duration": 1.0
    },
    {
      "keystrokes": "sed -n '1,200p' /app/docs/layout.md\n",
      "duration": 0.1
    },
    {
      "keystrokes": "sed -n '1,200p' /app/scripts/run-matrix.sh\n",
      "duration": 0.1
    },
    {
      "keystrokes": "sed -n '1,200p' /app/scripts/run-one.sh\n",
      "duration": 0.1
    },
    {
      "keystrokes": "rm -rf /app/build && mkdir -p /app/build\n",
      "duration": 1.0
    },
    {
      "keystrokes": "cmake -S /app -B /app/build -DCMAKE_BUILD_TYPE=Release\n",
      "duration": 10.0
    },
    {
      "keystrokes": "cmake --build /app/build -j\"$(nproc)\"\n",
      "duration": 20.0
    },
    {
      "keystrokes": "mkdir -p /app/output && rm -f /app/output/*audit.json\n",
      "duration": 0.1
    },
    {
      "keystrokes": "bash /app/scripts/run-matrix.sh\n",
      "duration": 20.0
    },
    {
      "keystrokes": "ls -la /app/output\n",
      "duration": 0.1
    },
    {
      "keystrokes": "python3 - <<'PY'\nimport json\np='/app/output/solver-audit.json'\nwith open(p) as f: j=json.load(f)\nprint('keys:',sorted(j.keys()))\nprint('cases:',len(j.get('cases',[])))\nfail=[c for c in j.get('cases',[]) if not c.get('ok',False) or not c.get('residual_agrees',False) or c.get('hit_limit',False)]\nprint('problem_cases:',len(fail))\nfor c in fail[:50]:\n    print(c.get('name'), 'ok=',c.get('ok'), 'res_agree=',c.get('residual_agrees'), 'hit_limit=',c.get('hit_limit'), 'it=',c.get('iterations'), 'final=',c.get('final_residual'), 'reported=',c.get('reported_residual'))\nPY\n",
      "duration": 1.0
    }
  ],
  "task_complete": false
}

